import React, { useState, useEffect } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Navbar.css';

const Navbar = () => {
  const { user, logout, isAuthenticated, isAdmin } = useAuth();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    logout();
    setMenuOpen(false);
    navigate('/');
  };

  const closeMenu = () => setMenuOpen(false);

  return (
    <nav className={`navbar ${scrolled ? 'navbar-scrolled' : ''}`} id="main-navbar">
      <div className="navbar-container">
        {/* Logo */}
        <Link to="/" className="navbar-logo" onClick={closeMenu} id="nav-logo">
          <span className="logo-icon">💜</span>
          <span className="logo-text">Fund<span className="logo-accent">It</span></span>
        </Link>

        {/* Desktop Nav Links */}
        <div className="navbar-links" id="nav-links">
          <NavLink
            to="/"
            className={({ isActive }) => `nav-link ${isActive ? 'nav-link-active' : ''}`}
            id="nav-home"
            end
          >
            Campaigns
          </NavLink>

          {isAuthenticated() && (
            <NavLink
              to="/create-campaign"
              className={({ isActive }) => `nav-link ${isActive ? 'nav-link-active' : ''}`}
              id="nav-create"
            >
              + Start Campaign
            </NavLink>
          )}

          {isAdmin() && (
            <NavLink
              to="/admin"
              className={({ isActive }) => `nav-link ${isActive ? 'nav-link-active' : ''}`}
              id="nav-admin"
            >
              Admin
            </NavLink>
          )}
        </div>

        {/* Auth Buttons */}
        <div className="navbar-auth" id="nav-auth">
          {isAuthenticated() ? (
            <div className="user-menu" id="user-menu-desktop">
              <Link to="/profile" className="user-avatar" title={user.name} id="user-avatar-desktop">
                {user.name.charAt(0).toUpperCase()}
              </Link>
              <Link to="/profile" className="user-name" id="user-display-name">{user.name.split(' ')[0]}</Link>
              <button
                className="btn btn-secondary btn-sm"
                onClick={handleLogout}
                id="btn-logout-desktop"
              >
                Logout
              </button>
            </div>
          ) : (
            <div className="auth-buttons" id="auth-buttons-desktop">
              <Link to="/login" className="btn btn-secondary btn-sm" id="nav-login-btn">
                Log In
              </Link>
              <Link to="/register" className="btn btn-primary btn-sm" id="nav-register-btn">
                Sign Up
              </Link>
            </div>
          )}
        </div>

        {/* Mobile Hamburger */}
        <button
          className={`hamburger ${menuOpen ? 'hamburger-open' : ''}`}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
          id="hamburger-btn"
        >
          <span></span>
          <span></span>
          <span></span>
        </button>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="mobile-menu" id="mobile-menu">
          <NavLink to="/" className="mobile-nav-link" onClick={closeMenu} end id="mobile-nav-home">
            🏠 Campaigns
          </NavLink>

          {isAuthenticated() && (
            <NavLink
              to="/create-campaign"
              className="mobile-nav-link"
              onClick={closeMenu}
              id="mobile-nav-create"
            >
              ✨ Start a Campaign
            </NavLink>
          )}

          {isAdmin() && (
            <NavLink
              to="/admin"
              className="mobile-nav-link"
              onClick={closeMenu}
              id="mobile-nav-admin"
            >
              ⚙️ Admin Dashboard
            </NavLink>
          )}

          <div className="mobile-auth">
            {isAuthenticated() ? (
              <>
                <Link to="/profile" className="mobile-nav-link" onClick={closeMenu} id="mobile-nav-profile">
                  👤 My Profile
                </Link>
                <button
                  className="btn btn-secondary btn-full"
                  onClick={handleLogout}
                  id="btn-logout-mobile"
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                <Link
                  to="/login"
                  className="btn btn-secondary btn-full"
                  onClick={closeMenu}
                  id="mobile-login-btn"
                >
                  Log In
                </Link>
                <Link
                  to="/register"
                  className="btn btn-primary btn-full"
                  onClick={closeMenu}
                  id="mobile-register-btn"
                >
                  Sign Up
                </Link>
              </>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
